parameters.jsCode:
const cliente = $input.item.json;
const cron = (cliente.config && cliente.config.apify && cliente.config.apify.cron_cadence_per_function) || {};
const tier = (cliente.config && cliente.config.apify && cliente.config.apify.plan_tier) || 'basic';
const scopeFunctions = ["instagram_scraper","facebook_ads_library_scraper","linkedin_company_scraper"];
const activas = scopeFunctions.filter(fn => cron[fn] != null);
return activas.map(fn => ({
  json: { client_id: cliente.id, client_name: cliente.name, apify_function: fn, cadence: cron[fn], tier }
}));

parameters.jsonBody:
={{ JSON.stringify({
  client_id: $json.client_id,
  apify_function: $json.apify_function,
  destination: "brain_rag",
  dry_run: true,
  source_table: "client_competitive_landscape",
  metadata: {
    calling_workflow_id: $workflow.id,
    calling_workflow_execution_id: $execution.id,
    scope: "journey_b_onboard",
    sprint: "9-cleanup-wire-6-critical-journey-b-DISCONNECTED-alta-sensibilidad",
    tier: $json.tier,
    cadence: $json.cadence
  }
}) }}

parameters.jsCode:
const items = $input.all();
const summary = { total_calls: items.length, successes: 0, errors: 0, skipped_gate: 0, by_function: {} };
for (const it of items) {
  const r = it.json || {};
  const fn = r.apify_function || 'unknown';
  summary.by_function[fn] = (summary.by_function[fn] || 0) + 1;
  if (r.status === 'skipped' || r.skip_reason) summary.skipped_gate++;
  else if (r.success === false || r.error) summary.errors++;
  else summary.successes++;
}
return [{ json: { scope: 'journey_b_onboard', destination_table: 'client_competitive_landscape', summary, ran_at: new Date().toISOString() } }];

